/* Kart/Stack Tasarımı */

.price-cards {

display: flex;

flex-direction: column;

gap: 15px; /* Kartlar arası boşluk */

}

.price-card {

border: 1px solid #ccc;

border-radius: 8px;

padding: 12px 16px;

background-color: #fafafa;

box-shadow: 0 2px 5px rgba(0,0,0,0.05);

}

.card-row {

margin-bottom: 6px;

font-size: 1em;

}

.card-row strong {

color: #2a6ebb; /* Başlık rengi */

}

.et-fiyat-baslik {

font-size: 18px;

font-weight: 600;

margin-bottom: 12px;

}

.et-fiyatlari {

width: 100%;

border-collapse: collapse;

font-size: 15px;

}

.et-fiyatlari thead {

background: rgba(0,0,0,0.04);

}

.et-fiyatlari th,

.et-fiyatlari td {

padding: 10px;

border-bottom: 1px solid #eee;

text-align: left;

}

.fiyat {

font-weight: 700;

color: #1a7f37;

}

/* Mobil Kart Tasarımı */

@media (max-width: 768px) {

.et-fiyatlari thead {

display: none;

}

.et-fiyatlari,

.et-fiyatlari tbody,

.et-fiyatlari tr,

.et-fiyatlari td {

display: block;

width: 100%;

}

.et-fiyatlari tr {

background: #fff;

border: 1px solid #eee;

border-radius: 10px;

padding: 14px;

margin-bottom: 12px;

box-shadow: 0 2px 8px rgba(0,0,0,0.04);

}

.et-fiyatlari td {

border: none;

padding: 6px 0;

}

.et-fiyatlari td::before {

content: attr(data-label);

font-weight: 600;

display: block;

color: #666;

font-size: 13px;

margin-bottom: 2px;

}

.fiyat {

font-size: 16px;

}

}
